import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import type { AppTheme, BuiltInThemeId } from "@t3tools/contracts";
import { BUILT_IN_THEMES, BUILT_IN_THEME_IDS, isBuiltInThemeId } from "@t3tools/shared/theme";

// ─── Storage ───────────────────────────────────────────────────────────────

const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";

function readStoredColorThemeId(): BuiltInThemeId | null {
  try {
    const raw = localStorage.getItem(COLOR_THEME_STORAGE_KEY);
    if (raw && isBuiltInThemeId(raw)) return raw;
  } catch {
    // localStorage unavailable
  }
  return null;
}

// ─── DOM application ───────────────────────────────────────────────────────

/**
 * Applies a color theme by writing CSS custom properties as inline styles on
 * the root element. Inline styles win over every stylesheet rule, so the
 * chosen palette always takes effect regardless of the active dark-mode class.
 *
 * Pass `null` to clear any previously applied color-theme overrides and fall
 * back to the base light/dark palette.
 */
function applyColorTheme(id: BuiltInThemeId | null): void {
  const root = document.documentElement;

  if (id === null) {
    // Remove all color-theme overrides, restoring the base palette.
    const propsToRemove = [
      "--t3-bg",
      "--t3-fg",
      "--t3-accent",
      "--t3-sidebar",
      "--t3-editor",
      "--t3-terminal",
      "--t3-status-bar",
      "--background",
      "--foreground",
      "--card",
      "--card-foreground",
      "--primary",
      "--primary-foreground",
      "--ring",
    ];
    for (const prop of propsToRemove) root.style.removeProperty(prop);
    root.removeAttribute("data-color-theme");
    return;
  }

  const theme = BUILT_IN_THEMES[id];
  const c = theme.colors;

  // Theme-specific surface variables (available everywhere via var(--t3-*))
  root.style.setProperty("--t3-bg", c.background);
  root.style.setProperty("--t3-fg", c.foreground);
  root.style.setProperty("--t3-accent", c.accent);
  root.style.setProperty("--t3-sidebar", c.sidebar);
  root.style.setProperty("--t3-editor", c.editor);
  root.style.setProperty("--t3-terminal", c.terminal);
  root.style.setProperty("--t3-status-bar", c.statusBar);

  // Override semantic tokens so all existing Tailwind utilities pick up the
  // new palette automatically (--background, --card, --primary, etc.)
  root.style.setProperty("--background", c.background);
  root.style.setProperty("--foreground", c.foreground);
  root.style.setProperty("--card", c.sidebar);
  root.style.setProperty("--card-foreground", c.foreground);
  root.style.setProperty("--primary", c.accent);
  root.style.setProperty("--primary-foreground", "#ffffff");
  root.style.setProperty("--ring", c.accent);

  // Mark the root so CSS can scope additional theme-specific rules if needed.
  root.setAttribute("data-color-theme", id);

  // Sync the dark-mode class so browser chrome and system UI match.
  root.classList.toggle("dark", theme.isDark);
}

// Apply immediately on module load to prevent a flash of unstyled content.
applyColorTheme(readStoredColorThemeId());

// ─── External store ────────────────────────────────────────────────────────

let colorThemeListeners: Array<() => void> = [];
let currentColorThemeId: BuiltInThemeId | null = readStoredColorThemeId();

function emitColorThemeChange(): void {
  for (const listener of colorThemeListeners) listener();
}

function subscribeColorTheme(listener: () => void): () => void {
  colorThemeListeners.push(listener);

  // Sync across tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key !== COLOR_THEME_STORAGE_KEY) return;
    const next = readStoredColorThemeId();
    if (next !== currentColorThemeId) {
      currentColorThemeId = next;
      applyColorTheme(next);
      emitColorThemeChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    colorThemeListeners = colorThemeListeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

function getColorThemeSnapshot(): BuiltInThemeId | null {
  return currentColorThemeId;
}

// ─── Context ───────────────────────────────────────────────────────────────

export interface ColorThemeContextValue {
  /** Currently active theme ID, or `null` when using system defaults. */
  colorThemeId: BuiltInThemeId | null;
  /** Full descriptor of the active theme, or `null` when using system defaults. */
  colorTheme: AppTheme | null;
  /** Switch to a different built-in theme, or pass `null` to clear. */
  setColorThemeId: (id: BuiltInThemeId | null) => void;
  /** Ordered list of all available built-in theme IDs. */
  allThemeIds: readonly BuiltInThemeId[];
}

const ColorThemeContext = createContext<ColorThemeContextValue | null>(null);

/**
 * Returns the active color-theme context.
 * Must be called inside a `<ThemeProvider>`.
 */
export function useColorTheme(): ColorThemeContextValue {
  const ctx = useContext(ColorThemeContext);
  if (!ctx) throw new Error("useColorTheme must be used inside <ThemeProvider>");
  return ctx;
}

// ─── Provider ──────────────────────────────────────────────────────────────

/**
 * Provides the color-theme context to the component tree and ensures the
 * selected palette is applied to the DOM whenever it changes.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const colorThemeId = useSyncExternalStore(subscribeColorTheme, getColorThemeSnapshot);
  const colorTheme = colorThemeId ? BUILT_IN_THEMES[colorThemeId] : null;

  const setColorThemeId = useCallback((id: BuiltInThemeId | null) => {
    try {
      if (id === null) {
        localStorage.removeItem(COLOR_THEME_STORAGE_KEY);
      } else {
        localStorage.setItem(COLOR_THEME_STORAGE_KEY, id);
      }
    } catch {
      // Ignore storage errors
    }
    currentColorThemeId = id;
    applyColorTheme(id);
    emitColorThemeChange();
  }, []);

  // Keep DOM in sync on mount and after hydration
  useEffect(() => {
    applyColorTheme(colorThemeId);
  }, [colorThemeId]);

  const value: ColorThemeContextValue = {
    colorThemeId,
    colorTheme,
    setColorThemeId,
    allThemeIds: BUILT_IN_THEME_IDS,
  };

  return (
    <ColorThemeContext.Provider value={value}>
      {children}
    </ColorThemeContext.Provider>
  );
}

