input.content:
import type { BuiltInThemeId, ThemeColors } from "@t3tools/contracts";
import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { useColorTheme } from "./ThemeProvider";

/**
 * A radio-group that lets the user choose one of the built-in T3 Code color
 * themes. Each option includes a miniature swatch previewing the sidebar,
 * editor, and status-bar colors of that theme.
 *
 * Renders an additional "System Default" option that clears any explicit
 * color-theme selection and falls back to the base light/dark palette.
 */
export function ThemeSelector() {
  const { colorThemeId, setColorThemeId, allThemeIds } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme preference">
      {/* System default — clears any override */}
      <ThemeOption
        id={null}
        name="System Default"
        isDark={null}
        colors={null}
        selected={colorThemeId === null}
        onSelect={() => setColorThemeId(null)}
      />

      {allThemeIds.map((id) => {
        const theme = BUILT_IN_THEMES[id];
        return (
          <ThemeOption
            key={id}
            id={id}
            name={theme.name}
            isDark={theme.isDark}
            colors={theme.colors}
            selected={colorThemeId === id}
            onSelect={() => setColorThemeId(id)}
          />
        );
      })}
    </div>
  );
}

// ─── Internal pieces ───────────────────────────────────────────────────────

interface ThemeOptionProps {
  id: BuiltInThemeId | null;
  name: string;
  isDark: boolean | null;
  colors: ThemeColors | null;
  selected: boolean;
  onSelect: () => void;
}

function ThemeOption({ id, name, isDark, colors, selected, onSelect }: ThemeOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={onSelect}
      className={[
        "flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent hover:text-foreground",
      ].join(" ")}
    >
      {/* Swatch or placeholder */}
      {colors ? (
        <ColorSwatch colors={colors} />
      ) : (
        <DefaultSwatch />
      )}

      {/* Labels */}
      <span className="flex flex-1 flex-col gap-0.5">
        <span className="text-sm font-medium">{name}</span>
        <span className="text-xs text-muted-foreground">
          {isDark === null
            ? "Use the base light/dark palette"
            : isDark
              ? "Dark color scheme"
              : "Light color scheme"}
        </span>
      </span>

      {/* Active badge */}
      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

/** Mini preview of the theme's key surface colors. */
function ColorSwatch({ colors }: { colors: ThemeColors }) {
  return (
    <div
      aria-hidden="true"
      className="relative flex h-9 w-14 shrink-0 overflow-hidden rounded-md border border-black/10 dark:border-white/10"
    >
      {/* Sidebar strip */}
      <div
        className="h-full w-[30%] shrink-0"
        style={{ background: colors.sidebar }}
      />

      {/* Main content area */}
      <div className="flex flex-1 flex-col">
        {/* Editor surface */}
        <div className="flex-1" style={{ background: colors.editor }} />
        {/* Status bar */}
        <div className="h-2" style={{ background: colors.statusBar }} />
      </div>

      {/* Accent dot */}
      <span
        className="absolute right-1 top-1 h-2 w-2 rounded-full ring-1 ring-black/10"
        style={{ background: colors.accent }}
      />
    </div>
  );
}

/** Placeholder swatch shown for the "System Default" option. */
function DefaultSwatch() {
  return (
    <div
      aria-hidden="true"
      className="flex h-9 w-14 shrink-0 items-center justify-center overflow-hidden rounded-md border border-dashed border-border bg-muted text-[9px] font-semibold uppercase tracking-widest text-muted-foreground"
    >
      Auto
    </div>
  );
}

